#include <stdio.h>

long fibonacciIterative(int n) {
    if (n <= 1) return n;

    long a = 0, b = 1;
    for (int i = 2; i <= n; i++) {
        long temp = a + b;
        a = b;
        b = temp;
    }
    return b;
}

long fibonacciRecursive(int n) {
    if (n <= 1) return n;
    return fibonacciRecursive(n - 1) + fibonacciRecursive(n - 2);
}

int main() {
    printf("Iteratif Fibonacci (0-10):\n");
    for (int i = 0; i <= 10; i++) {
        printf("%ld ", fibonacciIterative(i));
    }
    printf("\n");

    printf("\nRecursive Fibonacci (0-10):\n");
    for (int i = 0; i <= 10; i++) {
        printf("%ld ", fibonacciRecursive(i));
    }
    printf("\n");

    printf("\n20. Fibonacci sayisi: %ld\n", fibonacciIterative(20));

    return 0;
}
